const planMonths={Monthly:1,Quarterly:3,"Half-Yearly":6,Annual:12};
const renewalDate=m=>{if(!m.joinDate)return null;const d=new Date(m.joinDate);d.setMonth(d.getMonth()+(planMonths[m.plan]||1));return d.toISOString().split("T")[0];};
const daysUntil=ds=>{if(!ds)return null;const diff=new Date(ds)-new Date(today());return Math.ceil(diff/(1000*60*60*24));};
const renewalStatus=m=>{const d=daysUntil(renewalDate(m));if(d===null)return{label:"Unknown",color:"#555",days:null};if(d<0)return{label:"Expired "+Math.abs(d)+"d ago",color:"#ef4444",days:d};if(d<=7)return{label:"Expires in "+d+"d",color:"#ef4444",days:d};if(d<=30)return{label:"Expires in "+d+"d",color:"#d97706",days:d};return{label:"Active · "+d+"d left",color:"#059669",days:d};};
