function calcN(w,h,age,gender,goal,act){
  const bmr=gender==="M"?88.362+13.397*w+4.799*h-5.677*age:447.593+9.247*w+3.098*h-4.33*age;
  const tdee=bmr*(ACT_MUL[act]||1.55);
  const {pct,adj}=GOAL_CFG[goal]||GOAL_CFG.Maintenance;
  const cal=Math.round(tdee+adj);
  return{bmr:Math.round(bmr),tdee:Math.round(tdee),cal,protein:Math.round(cal*pct[0]/4),carbs:Math.round(cal*pct[1]/4),fat:Math.round(cal*pct[2]/9),water:+(w*35/1000).toFixed(1)};
}

