  const addExpense=(e)=>setExpenses(p=>[...p,{...e,branchId:activeBranchId}]);
  const addTrainer=(t)=>setTr(p=>[...p,{...t,branchId:activeBranchId}]);
  const addEnquiry=(e)=>setEnq(p=>[...p,{...e,branchId:activeBranchId}]);

  const birthdays=bMembers.filter(m=>m.dob&&m.dob.slice(5)===todayMD);
  const overdueCount=bFees.filter(f=>f.status==="Overdue").length;
