            <span style={{fontWeight:800,fontSize:mob?13:14,color:"#fff"}}>{NAV.find(n=>n.id===page)?.label}</span>
            {!mob&&!crossBranchView&&<div style={{background:(activeBranch?.color||R)+"22",border:`1px solid ${activeBranch?.color||R}44`,color:activeBranch?.color||R,padding:"2px 10px",borderRadius:20,fontSize:10,fontWeight:700,marginLeft:4}}>🏢 {activeBranch?.shortName}</div>}
            {!mob&&crossBranchView&&<div style={{background:"#d9770622",border:"1px solid #d9770644",color:"#d97706",padding:"2px 10px",borderRadius:20,fontSize:10,fontWeight:700,marginLeft:4}}>📊 All Branches</div>}
